import{_ as d,o as a,c as r,ak as e}from"./chunks/framework.24mNDJkT.js";const p=JSON.parse('{"title":"OpenClaw 是什么","description":"","frontmatter":{},"headers":[],"relativePath":"AI/OpenClaw/01.OpenClaw 是什么.md","filePath":"AI/OpenClaw/01.OpenClaw 是什么.md","lastUpdated":0}'),l={name:"AI/OpenClaw/01.OpenClaw 是什么.md"};function n(o,t,h,i,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="openclaw-是什么" tabindex="-1">OpenClaw 是什么 <a class="header-anchor" href="#openclaw-是什么" aria-label="Permalink to “OpenClaw 是什么”">​</a></h1><h2 id="一、概念" tabindex="-1">一、概念 <a class="header-anchor" href="#一、概念" aria-label="Permalink to “一、概念”">​</a></h2><h3 id="一句话介绍" tabindex="-1">一句话介绍 <a class="header-anchor" href="#一句话介绍" aria-label="Permalink to “一句话介绍”">​</a></h3><p><strong>OpenClaw</strong> 是一个<strong>开源的 AI 智能体 Gateway 网关</strong>，可以在本地部署 AI 助手，访问本地文件，并通过多个平台（飞书、企微、QQ 等）随时使用。</p><blockquote><p>📌 <strong>名称演变</strong>：原名 Clawdbot → 过渡名 Moltbot → 最终定名 OpenClaw（2026年1月30日），三个名字本质是同一个项目。</p></blockquote><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to “核心能力”">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>🏠 <strong>本地部署</strong></td><td>在自己的电脑上运行，数据隐私有保障</td></tr><tr><td>📁 <strong>文件访问</strong></td><td>搜索、读取、编辑电脑上的文件</td></tr><tr><td>🔌 <strong>无限扩展</strong></td><td>通过 Skills（技能）系统扩展功能</td></tr><tr><td>💬 <strong>多平台使用</strong></td><td>支持飞书、企微、钉钉、QQ、Telegram、Discord 等</td></tr><tr><td>💰 <strong>成本可控</strong></td><td>使用自己的 API，费用透明</td></tr></tbody></table><h3 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to “核心组件”">​</a></h3><ol><li><strong>Gateway 网关</strong> - 中央调度站，连接各聊天平台，管理会话和路由 <ul><li>默认地址：<code>http://127.0.0.1:18789/</code></li><li>配置文件：<code>~/.openclaw/openclaw.json</code></li></ul></li><li><strong>AI 智能体</strong> - 支持 Claude、GPT、Gemini、DeepSeek、Kimi 等模型</li><li><strong>Skills 技能系统</strong> - 预装 49 个内置技能，涵盖文件管理、知识管理、自动化等</li><li><strong>ClawHub</strong> - 技能市场，可下载和分享 Skills</li></ol><hr><h2 id="二、为什么选择-openclaw" tabindex="-1">二、为什么选择 OpenClaw <a class="header-anchor" href="#二、为什么选择-openclaw" aria-label="Permalink to “二、为什么选择 OpenClaw”">​</a></h2><h3 id="与在线-ai-的本质区别" tabindex="-1">与在线 AI 的本质区别 <a class="header-anchor" href="#与在线-ai-的本质区别" aria-label="Permalink to “与在线 AI 的本质区别”">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>OpenClaw</th><th>ChatGPT/Claude 网页版</th></tr></thead><tbody><tr><td>部署方式</td><td>本地/云端</td><td>在线服务</td></tr><tr><td>数据隐私</td><td>✅ 完全掌控</td><td>⚠️ 上传到服务器</td></tr><tr><td>本地文件访问</td><td>✅ 支持</td><td>❌ 不支持</td></tr><tr><td>系统操作</td><td>✅ 支持</td><td>❌ 不支持</td></tr><tr><td>功能扩展</td><td>✅ Skills 系统</td><td>❌ 固定功能</td></tr><tr><td>成本</td><td>按需付费</td><td>订阅制</td></tr><tr><td>多平台集成</td><td>✅ 支持</td><td>⚠️ 有限</td></tr></tbody></table><p><strong>简单类比</strong>：</p><ul><li>ChatGPT/Claude：像在网吧上网，方便但受限</li><li>OpenClaw：像自己的电脑，自由但需要配置</li></ul><h3 id="五大核心优势" tabindex="-1">五大核心优势 <a class="header-anchor" href="#五大核心优势" aria-label="Permalink to “五大核心优势”">​</a></h3><h4 id="_1-本地部署-保护隐私" tabindex="-1">1. 本地部署，保护隐私 <a class="header-anchor" href="#_1-本地部署-保护隐私" aria-label="Permalink to “1. 本地部署，保护隐私”">​</a></h4><ul><li>敏感文件无需上传云端，完全在本地处理</li><li>适合处理财务报表、合同等机密文档</li></ul><h4 id="_2-访问本地文件和系统" tabindex="-1">2. 访问本地文件和系统 <a class="header-anchor" href="#_2-访问本地文件和系统" aria-label="Permalink to “2. 访问本地文件和系统”">​</a></h4><ul><li>可直接搜索电脑上的所有文件</li><li>支持日历、备忘录、截图等系统操作</li><li><strong>示例</strong>：&quot;帮我找一下我电脑上的一张发票，里面详情是买了一个跑步机&quot; → AI 秒找到并发送文件</li></ul><h4 id="_3-可扩展的-skills-生态" tabindex="-1">3. 可扩展的 Skills 生态 <a class="header-anchor" href="#_3-可扩展的-skills-生态" aria-label="Permalink to “3. 可扩展的 Skills 生态”">​</a></h4><ul><li>预装 49 个内置技能，开箱即用</li><li>技能涵盖：文件管理、知识管理、日程管理、自动化、工具类（截图、翻译、画图、视频生成）</li><li>可通过 ClawHub 下载更多技能（1715+ 个）</li></ul><h4 id="_4-多平台支持" tabindex="-1">4. 多平台支持 <a class="header-anchor" href="#_4-多平台支持" aria-label="Permalink to “4. 多平台支持”">​</a></h4><ul><li>企业微信、钉钉、飞书、QQ、Telegram、Discord</li><li>在任何平台发消息，AI 都能响应</li></ul><h4 id="_5-成本可控" tabindex="-1">5. 成本可控 <a class="header-anchor" href="#_5-成本可控" aria-label="Permalink to “5. 成本可控”">​</a></h4><table tabindex="0"><thead><tr><th>服务</th><th>月费</th></tr></thead><tbody><tr><td>ChatGPT Plus</td><td>~140 元</td></tr><tr><td>Claude Pro</td><td>~140 元</td></tr><tr><td><strong>OpenClaw + DeepSeek</strong></td><td><strong>5-30 元</strong></td></tr><tr><td><strong>OpenClaw + Kimi</strong></td><td><strong>10-50 元</strong></td></tr></tbody></table><p>💡 <strong>省钱技巧</strong>：使用国产大模型可节省 50%-70% 成本</p><hr><h2 id="三、openclaw-vs-主流-ai-工具" tabindex="-1">三、OpenClaw vs 主流 AI 工具 <a class="header-anchor" href="#三、openclaw-vs-主流-ai-工具" aria-label="Permalink to “三、OpenClaw vs 主流 AI 工具”">​</a></h2><h3 id="功能对比" tabindex="-1">功能对比 <a class="header-anchor" href="#功能对比" aria-label="Permalink to “功能对比”">​</a></h3><table tabindex="0"><thead><tr><th>功能特性</th><th>OpenClaw</th><th>ChatGPT Plus</th><th>Cursor</th><th>Claude Pro</th></tr></thead><tbody><tr><td>本地文件访问</td><td>✅ 完整支持</td><td>❌ 不支持</td><td>✅ 支持</td><td>❌ 不支持</td></tr><tr><td>系统操作</td><td>✅ 日历/备忘录/截图</td><td>❌ 不支持</td><td>⚠️ 有限</td><td>❌ 不支持</td></tr><tr><td>多平台集成</td><td>✅ 飞书/企微/钉钉/QQ</td><td>⚠️ 有限</td><td>❌ 不支持</td><td>⚠️ 有限</td></tr><tr><td>Skills 扩展</td><td>✅ 1715+</td><td>❌ 不支持</td><td>⚠️ 插件</td><td>❌ 不支持</td></tr><tr><td>多模型切换</td><td>✅ 随意切换</td><td>❌ 固定 GPT</td><td>✅ 支持</td><td>❌ 固定 Claude</td></tr><tr><td>代码能力</td><td>✅ 强</td><td>⚠️ 中等</td><td>✅ 强</td><td>✅ 强</td></tr><tr><td>自动化任务</td><td>✅ 完整支持</td><td>❌ 不支持</td><td>❌ 不支持</td><td>❌ 不支持</td></tr></tbody></table><h3 id="年度成本对比" tabindex="-1">年度成本对比 <a class="header-anchor" href="#年度成本对比" aria-label="Permalink to “年度成本对比”">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>OpenClaw</th><th>ChatGPT Plus</th><th>Cursor</th><th>Claude Pro</th></tr></thead><tbody><tr><td><strong>月费</strong></td><td>5-50 元</td><td>140 元</td><td>140 元</td><td>140 元</td></tr><tr><td><strong>年费</strong></td><td>60-600 元</td><td>1680 元</td><td>1680 元</td><td>1680 元</td></tr><tr><td><strong>节省</strong></td><td>-</td><td>节省 73%-96%</td><td>节省 73%-96%</td><td>节省 73%-96%</td></tr></tbody></table><h3 id="能力维度对比" tabindex="-1">能力维度对比 <a class="header-anchor" href="#能力维度对比" aria-label="Permalink to “能力维度对比”">​</a></h3><table tabindex="0"><thead><tr><th>能力维度</th><th>OpenClaw</th><th>Claude Code</th><th>Cursor</th><th>ChatGPT</th></tr></thead><tbody><tr><td>任务规划</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐⭐</td></tr><tr><td>自动执行</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐</td></tr><tr><td>自我修复</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐</td><td>⭐⭐</td><td>⭐</td></tr><tr><td>工程级操作</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>⭐⭐</td></tr><tr><td>本地自动化</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐</td><td>⭐⭐</td><td>⭐</td></tr><tr><td>代码质量</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td></tr><tr><td>易用性</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td></tr></tbody></table><p><strong>核心差异</strong>：</p><ul><li><strong>OpenClaw</strong>：强在任务规划和自动执行完整工程流程</li><li><strong>Claude Code/Cursor</strong>：强在代码质量与理解</li><li><strong>ChatGPT</strong>：强在对话体验和易用性</li></ul><hr><h2 id="四、适用场景" tabindex="-1">四、适用场景 <a class="header-anchor" href="#四、适用场景" aria-label="Permalink to “四、适用场景”">​</a></h2><h3 id="✅-适合使用-openclaw-的场景" tabindex="-1">✅ 适合使用 OpenClaw 的场景 <a class="header-anchor" href="#✅-适合使用-openclaw-的场景" aria-label="Permalink to “✅ 适合使用 OpenClaw 的场景”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>具体应用</th></tr></thead><tbody><tr><td><strong>个人效率提升</strong></td><td>整理文档资料、管理日程任务、自动化重复工作</td></tr><tr><td><strong>知识管理</strong></td><td>网页文章存档、GitHub 项目管理、论文笔记整理、跨设备同步</td></tr><tr><td><strong>编程开发</strong></td><td>代码搜索理解、技术文档查询、开发环境配置、项目管理</td></tr><tr><td><strong>团队协作</strong></td><td>项目管理自动化、文档协作优化、会议记录整理、团队知识库建设</td></tr><tr><td><strong>创意工作</strong></td><td>AI 绘画工作流、视频脚本生成、多语言翻译、数据分析自动化</td></tr></tbody></table><h3 id="❌-不适合使用-openclaw-的场景" tabindex="-1">❌ 不适合使用 OpenClaw 的场景 <a class="header-anchor" href="#❌-不适合使用-openclaw-的场景" aria-label="Permalink to “❌ 不适合使用 OpenClaw 的场景”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>替代方案</th></tr></thead><tbody><tr><td><strong>纯在线对话</strong></td><td>ChatGPT 网页版（无需安装配置）</td></tr><tr><td><strong>专业代码编辑</strong></td><td>Cursor、GitHub Copilot（集成度更高）</td></tr><tr><td><strong>移动端为主</strong></td><td>ChatGPT App、Claude App（无需配置）</td></tr><tr><td><strong>不想折腾</strong></td><td>在线 AI 服务（开箱即用）</td></tr></tbody></table><h3 id="💡-最佳实践组合" tabindex="-1">💡 最佳实践组合 <a class="header-anchor" href="#💡-最佳实践组合" aria-label="Permalink to “💡 最佳实践组合”">​</a></h3><ul><li><strong>OpenClaw</strong>：日常工作助手（本地文件、自动化、多平台）</li><li><strong>Cursor</strong>：代码编辑</li><li><strong>ChatGPT</strong>：移动端对话</li></ul><hr><h2 id="五、本章小结" tabindex="-1">五、本章小结 <a class="header-anchor" href="#五、本章小结" aria-label="Permalink to “五、本章小结”">​</a></h2><p>✅ <strong>OpenClaw 是什么</strong>：本地 AI 助手，通过 Gateway 连接多个平台</p><p>✅ <strong>核心优势</strong>：本地部署、文件访问、可扩展、多平台、成本低</p><p>✅ <strong>与其他 AI 的区别</strong>：更适合作为个人工作助手</p><p>✅ <strong>适用场景</strong>：效率提升、知识管理、编程开发、团队协作</p><p>✅ <strong>不适合场景</strong>：纯对话、移动端为主、不想折腾</p>',52)])])}const c=d(l,[["render",n]]);export{p as __pageData,c as default};
